import{_ as t,o as e,c as r,a2 as d}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"基金交易规则","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/funds/fund-trading-rules.md","filePath":"zh-CN/funds-and-wealth/funds/fund-trading-rules.md"}'),l={name:"funds-and-wealth/funds/fund-trading-rules.md"};function i(h,a,n,o,s,u){return e(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="基金交易规则" tabindex="-1">基金交易规则 <a class="header-anchor" href="#基金交易规则" aria-label="Permalink to &quot;基金交易规则&quot;">​</a></h1><p>基金交易 T 日定义、买卖截止时间、撤单规则及交易金额要求。</p><h2 id="t-日定义" tabindex="-1">T 日定义 <a class="header-anchor" href="#t-日定义" aria-label="Permalink to &quot;T 日定义&quot;">​</a></h2><p>基金交易以每天 <strong>12:00（北京时间）</strong> 为当日截止时间。12:00 前提交的申请按当日（T 日）净值处理；12:00 后提交的申请，顺延至下一个交易日（T+1 日）处理。</p><h2 id="买入规则" tabindex="-1">买入规则 <a class="header-anchor" href="#买入规则" aria-label="Permalink to &quot;买入规则&quot;">​</a></h2><h3 id="正常买入流程" tabindex="-1">正常买入流程 <a class="header-anchor" href="#正常买入流程" aria-label="Permalink to &quot;正常买入流程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间节点</th><th>说明</th></tr></thead><tbody><tr><td>T 日 12:00 前提交</td><td>按 T 日净值确认</td></tr><tr><td>T+3 日</td><td>确认买入份额，份额到账</td></tr><tr><td>T+4 日起</td><td>可查看持有收益</td></tr></tbody></table><h3 id="撤单规则" tabindex="-1">撤单规则 <a class="header-anchor" href="#撤单规则" aria-label="Permalink to &quot;撤单规则&quot;">​</a></h3><ul><li>T 日 12:00 前，可撤销尚未确认的买入申请</li><li>T 日 12:00 后，买入申请不可撤单</li></ul><h2 id="卖出规则" tabindex="-1">卖出规则 <a class="header-anchor" href="#卖出规则" aria-label="Permalink to &quot;卖出规则&quot;">​</a></h2><h3 id="正常卖出流程" tabindex="-1">正常卖出流程 <a class="header-anchor" href="#正常卖出流程" aria-label="Permalink to &quot;正常卖出流程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间节点</th><th>说明</th></tr></thead><tbody><tr><td>T 日 12:00 前提交</td><td>按 T 日净值确认卖出金额</td></tr><tr><td>T+3 日</td><td>确认卖出净值，份额扣除</td></tr><tr><td>T+3 日起 7 个交易日内</td><td>资金到账</td></tr></tbody></table><h3 id="撤单规则-1" tabindex="-1">撤单规则 <a class="header-anchor" href="#撤单规则-1" aria-label="Permalink to &quot;撤单规则&quot;">​</a></h3><ul><li>T 日 12:00 前，可撤销尚未确认的卖出申请</li><li>T 日 12:00 后，卖出申请不可撤单</li></ul><h2 id="交易金额要求" tabindex="-1">交易金额要求 <a class="header-anchor" href="#交易金额要求" aria-label="Permalink to &quot;交易金额要求&quot;">​</a></h2><ul><li><strong>起购金额</strong>：首次买入的最低金额，以基金详情页显示为准</li><li><strong>最小卖出份额</strong>：每次卖出的最低份额数量，以基金详情页显示为准</li></ul><p>不同基金的起购金额和最小卖出份额可能不同，请以具体基金详情页的说明为准。</p><h2 id="字段说明" tabindex="-1">字段说明 <a class="header-anchor" href="#字段说明" aria-label="Permalink to &quot;字段说明&quot;">​</a></h2><h3 id="日涨跌幅" tabindex="-1">日涨跌幅 <a class="header-anchor" href="#日涨跌幅" aria-label="Permalink to &quot;日涨跌幅&quot;">​</a></h3><p>当日基金净值相对于上一交易日净值的变动百分比。</p><p>公式：日涨跌幅 = (今日单位净值 - 昨日单位净值) ÷ 昨日单位净值 × 100%</p><h3 id="待确认资金" tabindex="-1">待确认资金 <a class="header-anchor" href="#待确认资金" aria-label="Permalink to &quot;待确认资金&quot;">​</a></h3><p>已提交申请但尚未被基金公司确认的资金。买入申请在确认前，对应金额显示为待确认资金；确认后转换为持有份额。</p><h3 id="持有份额" tabindex="-1">持有份额 <a class="header-anchor" href="#持有份额" aria-label="Permalink to &quot;持有份额&quot;">​</a></h3><p>当前账户中已确认持有的基金份额数量。</p><h3 id="单位净值" tabindex="-1">单位净值 <a class="header-anchor" href="#单位净值" aria-label="Permalink to &quot;单位净值&quot;">​</a></h3><p>基金每份的当前价格，由基金公司每个交易日收盘后公布。已扣除管理费、托管费等费用。</p><h3 id="基金总额" tabindex="-1">基金总额 <a class="header-anchor" href="#基金总额" aria-label="Permalink to &quot;基金总额&quot;">​</a></h3><p>持有份额按当前单位净值折算的总市值。</p><p>公式：基金总额 = 持有份额 × 单位净值</p><h3 id="最新收益" tabindex="-1">最新收益 <a class="header-anchor" href="#最新收益" aria-label="Permalink to &quot;最新收益&quot;">​</a></h3><p>当日基金净值变动带来的收益（或亏损）金额。</p><p>公式：最新收益 = 持有份额 × (今日单位净值 - 昨日单位净值)</p><h3 id="持有收益" tabindex="-1">持有收益 <a class="header-anchor" href="#持有收益" aria-label="Permalink to &quot;持有收益&quot;">​</a></h3><p>从买入至今的累计盈亏金额，反映当前持仓的浮动盈亏。</p><p>公式：持有收益 = 基金总额 - 买入总成本</p><h3 id="累计收益" tabindex="-1">累计收益 <a class="header-anchor" href="#累计收益" aria-label="Permalink to &quot;累计收益&quot;">​</a></h3><p>历史上所有已完成交易（已赎回部分）的实际盈亏，加上当前持仓的浮动盈亏之和。</p><p>公式：累计收益 = 历史已实现盈亏 + 当前持有收益</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth/funds/fund-fees">基金收费</a> — 申购赎回费率与管理费说明</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth/funds/first-fund-regular-investment">完成首笔基金定投</a></li><li><a href="/wiki/funds-and-wealth/funds/fund-basics">基金</a></li><li><a href="/wiki/funds-and-wealth/funds/fund-fees">基金收费</a></li><li><a href="/wiki/funds-and-wealth/funds/fund-regular-investment">基金定投</a></li><li><a href="/wiki/funds-and-wealth">基金与理财</a></li></ul>',43)])])}const b=t(l,[["render",i]]);export{c as __pageData,b as default};
